CREATE DATABASE Shipway_database;

USE Shipway_database;

CREATE TABLE [Province]
(
	[ProvinceId] [varchar](20) NOT NULL PRIMARY KEY,
	[Name] [nvarchar](50) NULL,
	[Type] [nvarchar](50) NULL,
	[Region] [int] NULL
);

CREATE TABLE [District]
(
	[DistrictId] [varchar](20) NOT NULL PRIMARY KEY,
	[ProvinceId] [varchar](20) REFERENCES [Province]([ProvinceId]),
	[Name] [nvarchar](50) NULL,
	[Type] [nvarchar](50) NULL,
	[Location] [nvarchar](50) NULL
);

CREATE TABLE [Ward]
(
	[WardId] [varchar](20) NOT NULL PRIMARY KEY,
	[DistrictId] [varchar](20) REFERENCES [District]([DistrictId]),
	[Name] [nvarchar](50) NOT NULL,
	[Type] [nvarchar](50) NULL,
	[Region] [int] NULL,
);

CREATE TABLE [Agency]
(
	[AgencyId] [int] IDENTITY(1,1) NOT NULL PRIMARY KEY,
	[AgencyName] [nvarchar](50) NULL,
	[PhoneNumber] [nvarchar](50) NOT NULL,
	[Address] [nvarchar](200) NOT NULL,
	[ActivityTime] [nvarchar](200) NOT NULL,
	[WardId] [varchar](20) NULL REFERENCES [Ward]([WardId]),
	[IsCentralWarehouse] [bit],
);

CREATE TABLE [TypeUsers]
(
	TypeId int IDENTITY(1,1) NOT NULL PRIMARY KEY,
	TypeName nvarchar(255)
);

CREATE TABLE [Users]
(
	[Id] [int] IDENTITY(1,1) NOT NULL PRIMARY KEY,
	[UserName] [nvarchar](255),
	[Password] [nvarchar](255),
	[Email] [nvarchar](100),
	[PhoneNumber] [nvarchar](100),
	[Name] [nvarchar](100),
	[Address] [nvarchar](255),
	[WardId] [varchar](20) NULL REFERENCES [Ward]([WardId]),
	[TypeId] int REFERENCES [TypeUsers]([TypeId]),
	[AgencyId] [int] REFERENCES [Agency]([AgencyId])
);

CREATE TABLE [KindTimeReceived]
(
	[KindTimeReceivedId] [int] IDENTITY(1,1) PRIMARY KEY,
	[Name] [nvarchar](100),
	[NumberOfDay] [int]
);

CREATE TABLE [KindService]
(
	[KindServiceId] [int] IDENTITY(1,1) PRIMARY KEY,
	[KindServiceName] [nvarchar](100),
);

CREATE TABLE [Router]
(
	[RouterId] [int] IDENTITY(1,1) NOT NULL PRIMARY KEY,
	[RouterName] [nvarchar](50)
);

CREATE TABLE [ServiceCharge]
(
	[ServiceChargeId] [int] IDENTITY(1,1) PRIMARY KEY,
	[RouterId] [int] REFERENCES [Router]([RouterId]),
	[KindServiceId] [int] REFERENCES [KindService]([KindServiceId]),
	[KindTimeReceivedId] [int] REFERENCES [KindTimeReceived]([KindTimeReceivedId]),
	[Weigh] [int],
	[CostOderUrban] [int],
	[CostOderSubUrban] [int],
	[AddWeight] [int],
	[AddMoney] [int]
);

CREATE TABLE [ExhibitionStatus]
(
	[ExhibitionStatusId] [int] IDENTITY(1,1) PRIMARY KEY,
	[Name] [nvarchar](50)
);

CREATE TABLE [Exhibition]
(
	[ExhibitionId] [varchar](36) NOT NULL PRIMARY KEY,
	[SenderId] [int] REFERENCES [Users]([Id]),
	[ReceiverName] [nvarchar](100) NULL,
	[ReceiverPhoneNumber] [nvarchar](50) NULL,
	[ReceiverAddress] [nvarchar](500) NULL,
	[WardReceiveId] [varchar](20) NULL REFERENCES [Ward]([WardId]),
	[PackageWeigh] [int] NULL,
	[PackageLong] [int] NULL,
	[PackageWide] [int] NULL,
	[PackageHigh] [int] NULL,
	[Note] [nvarchar](500) NULL,
	[CreatedDate] [datetime] NULL,
	[CreatedUserId] [int] NULL REFERENCES [Users]([Id]),
	[LastModifiedDate] [datetime] NULL,
	[LastModifiedUserId] [int] NULL REFERENCES [Users]([Id]),
	[KindServiceId] [int] REFERENCES [KindService]([KindServiceId]),
	[Cost] [int] NULL,
	[ExhibitionStatusId] [int] NULL,
	[DayReceive] [datetime] NULL,
	[LocationSender] [nvarchar](500) NULL,
	[LocationReceive] [nvarchar](500) NULL,
	[IsSendToAgency] [bit] NULL,
	[AssignToAgencyId] [int] NULL REFERENCES [Agency]([AgencyId]),
	[GroupLump] [int] NULL,
	[NumberOfFailedDeliveries] [int] NULL,
	[AgencyId] [int] REFERENCES [Agency]([AgencyId])
);


CREATE TABLE [HistoryTrip]
(
	[HistoryTripId] [int] IDENTITY(1,1) PRIMARY KEY,
	[ExhibitionId] [varchar](36) REFERENCES [Exhibition]([ExhibitionId]),
	[DateTrip] [datetime] NULL,
	[ExhibitionStatusId] [int] NULL REFERENCES [ExhibitionStatus]([ExhibitionStatusId]),
	[CurrentAddress] [nvarchar](500) NULL,
	[Note] nvarchar(255)
);

CREATE TABLE AssignWork
(
	AssignWorkId int IDENTITY(1,1) PRIMARY KEY,
	ExhibitionId varchar(36) REFERENCES Exhibition(ExhibitionId),
	ShipperId int REFERENCES Users(Id),
	AssignWorkDate date,
	DeliveryDate date,
	Note nvarchar(255)
);


